import{_ as a,o,c as t,ag as d}from"./chunks/framework.CfGxNWra.js";const p=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":1780485959000}'),r={name:"changelog.md"};function i(n,e,s,l,c,h){return o(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to this project will be documented in this file.</p><p>The format is based on <a href="https://keepachangelog.com/en/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and this project adheres to <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="unreleased" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.10...HEAD" target="_blank" rel="noreferrer">Unreleased</a> <a class="header-anchor" href="#unreleased" aria-label="Permalink to &quot;[Unreleased]&quot;">​</a></h2><h2 id="_0-1-10-2026-06-04" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.9...v0.1.10" target="_blank" rel="noreferrer">0.1.10</a> - 2026-06-04 <a class="header-anchor" href="#_0-1-10-2026-06-04" aria-label="Permalink to &quot;[0.1.10] - 2026-06-04&quot;">​</a></h2><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><p><strong>&quot;Waiting for this message. This may take a while.&quot;</strong> — addressed three independent root causes that all surface as the same stuck-bubble symptom on the recipient&#39;s side:</p><ul><li><em>Missing <code>getMessage</code> callback.</em> Baileys&#39; documented remedy for retry-receipts. Implemented against a disk-persisted LRU (cap 1000) of sent messages under <code>${dataDir}/sent-cache/</code>, so when a recipient can&#39;t decrypt one of our outbound messages we re-encrypt against the freshly negotiated session and resend.</li><li><em>Torn signal-key writes on abrupt termination.</em> Baileys&#39; bundled <code>useMultiFileAuthState</code> writes <code>session-&lt;jid&gt;.json</code> with truncate-and-write-in-place — a SIGKILL mid-write (typical under <code>node --watch</code> in dev, or any hot restart) tears the JSON. On next start <code>JSON.parse</code> throws, Baileys treats the session as absent, and every subsequent message to that contact sticks. Replaced with <code>useAtomicAuthState</code> (<code>src/authState.js</code>): write-to-tmp + atomic <code>rename</code>.</li><li><em>Dual-identity routing for LID-routed contacts.</em> WhatsApp runs 1:1 chats over two parallel identities (<code>&lt;number&gt;@s.whatsapp.net</code> and <code>&lt;lid&gt;@lid</code>) with independent Signal sessions. Receiving on <code>@lid</code> and replying on <code>@s.whatsapp.net</code> desyncs the recipient&#39;s counter from ours. Wabox now records the LID for every phone number we see on <code>@lid</code> (persisted to <code>${dataDir}/lid-map.json</code>) and the outbox auto-rewrites bare-number / <code>@s.whatsapp.net</code> reply targets to the known LID. Groups and explicit <code>@lid</code>/<code>@broadcast</code>/<code>@newsletter</code> targets pass through unchanged. The <code>examples/wabox-claude-code.sh</code> bridge was also updated to reply on <code>from</code> directly so any consumer using it gets the right routing for free.</li></ul><p>A fresh re-pair is recommended if you&#39;d already accumulated stuck contacts from previous corrupted-state runs.</p></li><li><p><code>wabox config</code> / pairing no longer returns before WhatsApp on the phone has finished linking. Completion is now tied to Baileys&#39; <code>receivedPendingNotifications: true</code> (with a 30s safety cap) instead of a 1.5s post-open timer.</p></li><li><p>Noisy 408 &quot;Timed Out&quot; in <code>init queries</code>. The post-open <code>fetchProps / fetchBlocklist / fetchPrivacySettings</code> batch exists for WhatsApp Web UI parity and is unused here. Disabled via <code>fireInitQueries: false</code>.</p></li><li><p>Media re-upload option for <code>downloadMediaMessage</code> was silently dropped after Baileys renamed <code>reqMediaUpload</code> → <code>reuploadRequest</code>. Expired media URLs can be recovered again.</p></li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Baileys socket configuration aligned with 6.7.x best practices: <code>state.keys</code> wrapped in <code>makeCacheableSignalKeyStore</code> (in-memory read cache, fewer disk reads); <code>markOnlineOnConnect: false</code> (your phone keeps push-notifying while wabox runs); <code>shouldSyncHistoryMessage: () =&gt; false</code> (skip the history replay we don&#39;t use — <code>receivedPendingNotifications</code> lands in seconds instead of minutes on busy accounts).</li><li>Reconnect uses 1s → 30s exponential backoff instead of immediate retry; resets on a healthy <code>open</code>.</li></ul><h2 id="_0-1-9-2026-06-04" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.8...v0.1.9" target="_blank" rel="noreferrer">0.1.9</a> - 2026-06-04 <a class="header-anchor" href="#_0-1-9-2026-06-04" aria-label="Permalink to &quot;[0.1.9] - 2026-06-04&quot;">​</a></h2><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Inbox envelopes are now published atomically (write to a hidden temp name, then rename), so fast consumers reacting in milliseconds can no longer delete a partially-written <code>.json</code> and lose the read receipt that would have marked the message read.</li></ul><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>New <code>examples/wabox-claude-code.sh</code> — a ready-to-run bridge between wabox and the Claude Code CLI, with slash commands (<code>/model</code>, <code>/mode</code>, <code>/system</code>, <code>/help</code>) for per-conversation overrides.</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>PROCESSED_DIR</code> in the Claude Code bridge example is now configurable.</li></ul><h2 id="_0-1-8-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.7...v0.1.8" target="_blank" rel="noreferrer">0.1.8</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-8-2026-06-03" aria-label="Permalink to &quot;[0.1.8] - 2026-06-03&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Installable agent skill at <code>skills/wabox</code> (Agent Skills / skills.sh standard): <code>npx skills add rodgco/wabox</code> teaches a consumer agent the inbox/outbox contract and the read → remove → respond workflow.</li><li><code>INTEGRATION.md</code> — a guide for agents that consume the boxes (message/job formats, replies, reactions, content types, WhatsApp text formatting, the read-receipt lifecycle, and ready-to-use job examples). Shipped in the npm package.</li></ul><h2 id="_0-1-7-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.6...v0.1.7" target="_blank" rel="noreferrer">0.1.7</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-7-2026-06-03" aria-label="Permalink to &quot;[0.1.7] - 2026-06-03&quot;">​</a></h2><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><code>wabox update</code> could reinstall the version you already had because npm&#39;s cached <code>@latest</code> dist-tag was stale. It now resolves the concrete latest version with a fresh registry read and installs with <code>--prefer-online</code>.</li></ul><h2 id="_0-1-6-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.5...v0.1.6" target="_blank" rel="noreferrer">0.1.6</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-6-2026-06-03" aria-label="Permalink to &quot;[0.1.6] - 2026-06-03&quot;">​</a></h2><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Allow list now matches the sender&#39;s real phone number even when the chat is routed via a LID (<code>@lid</code>): it checks <code>senderPn</code>/<code>participantPn</code>, not just the chat JID. Previously messages from an allowed number could be wrongly rejected.</li></ul><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Inbox records now include the sender&#39;s resolved <code>number</code>, and the rejection log shows the real phone number (not the LID).</li></ul><h2 id="_0-1-5-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.4...v0.1.5" target="_blank" rel="noreferrer">0.1.5</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-5-2026-06-03" aria-label="Permalink to &quot;[0.1.5] - 2026-06-03&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Log rejected senders (phone number + name) at <code>info</code> level when the allow list blocks a message, so you can see who tried to reach a restricted inbox.</li></ul><h2 id="_0-1-4-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.3...v0.1.4" target="_blank" rel="noreferrer">0.1.4</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-4-2026-06-03" aria-label="Permalink to &quot;[0.1.4] - 2026-06-03&quot;">​</a></h2><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>wabox allow</code> command — manage who can reach the inbox by phone number (<code>list</code>/<code>add</code>/<code>remove</code>/<code>clear</code>), edited offline in <code>config.json</code> with the service restarted automatically.</li></ul><h2 id="_0-1-3-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.1...v0.1.3" target="_blank" rel="noreferrer">0.1.3</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-3-2026-06-03" aria-label="Permalink to &quot;[0.1.3] - 2026-06-03&quot;">​</a></h2><h3 id="added-5" tabindex="-1">Added <a class="header-anchor" href="#added-5" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Send a native WhatsApp read receipt (blue checkmarks) when a message&#39;s <code>.json</code> is removed from the inbox. The consumer owns inbox cleanup; deleting a file is the &quot;message processed&quot; signal.</li><li><code>wabox update</code> command — updates the global npm package and restarts the background service.</li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Quiet Baileys&#39; chatty internal logs by giving it its own logger (default <code>warn</code>, tunable via <code>BAILEYS_LOG_LEVEL</code>), so harmless app-state resync and init-query timeouts no longer flood the journal.</li></ul><blockquote><p>Note: version 0.1.2 was bumped during development but never published to npm; its logging change shipped as part of 0.1.3.</p></blockquote><h2 id="_0-1-1-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.0...v0.1.1" target="_blank" rel="noreferrer">0.1.1</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-1-2026-06-03" aria-label="Permalink to &quot;[0.1.1] - 2026-06-03&quot;">​</a></h2><h3 id="fixed-4" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-4" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Complete WhatsApp pairing reliably: reconnect on stream error 515 (&quot;restart required&quot;), which WhatsApp sends right after the QR scan. Pairing previously stopped at this point and appeared to fail.</li></ul><h2 id="_0-1-0-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/releases/tag/v0.1.0" target="_blank" rel="noreferrer">0.1.0</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-0-2026-06-03" aria-label="Permalink to &quot;[0.1.0] - 2026-06-03&quot;">​</a></h2><p>Initial release.</p><h3 id="added-6" tabindex="-1">Added <a class="header-anchor" href="#added-6" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>WhatsApp ↔ filesystem bridge built on <a href="https://github.com/WhiskeySockets/Baileys" target="_blank" rel="noreferrer">Baileys</a>: QR pairing with a persisted session and automatic reconnect.</li><li>Incoming messages (text + media) saved to an <code>inbox/</code> folder as JSON, with media downloaded alongside.</li><li>Outbox folder watched for outgoing jobs — send text, files, quoted replies, and emoji reactions.</li><li>Cross-platform CLI (<code>config</code>, <code>run</code>, <code>pair</code>, <code>status</code>, <code>uninstall</code>) with an interactive setup, native per-OS paths (XDG on Linux, Application Support on macOS, <code>%APPDATA%</code>/<code>%LOCALAPPDATA%</code> on Windows), and background-service install via systemd, launchd, or Windows Task Scheduler.</li><li>MIT license and contribution guidelines, including an AI-assistance policy.</li></ul>',46)])])}const m=a(r,[["render",i]]);export{p as __pageData,m as default};
